  1→import { useCallback, useEffect } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5→import { TOOLS } from '@/editor/tools';
  6→import { detectRooms } from '@/geometry/roomDetection';
  7→import { createRoom } from '@/domain/models';
  8→import { isTypingTarget } from '@/utils/keyboard';
  9→import {
 10→  NewIcon, SaveIcon, LoadIcon, UndoIcon, RedoIcon,
 11→  CopyIcon, CutIcon, PasteIcon,
 12→  SelectIcon, DimensionIcon, WallIcon, BeamIcon, StairIcon,
 13→  SectionCutIcon, SlabIcon, RoomIcon, DoorIcon, WindowIcon,
 14→  ColumnIcon, LandingIcon, RailingIcon,
 15→  KitchenTopIcon, ToiletIcon, LavatoryIcon, TableIcon, TVIcon, SofaIcon, BedIcon,
 16→  GridIcon, SnapIcon, DetectRoomsIcon,
 17→  SidebarIcon, PropertiesIcon,
 18→} from './ToolbarIcons';
 19→import { FIXTURE_TYPES } from '@/editor/tools';
 20→import styles from './Toolbar.module.css';
 21→
 22→const viewModes = [
 23→  { key: 'plan', label: 'Plan', viewMode: 'plan' },
 24→  { key: 'front', label: 'Front', viewMode: 'elevation_front' },
 25→  { key: 'rear', label: 'Rear', viewMode: 'elevation_rear' },
 26→  { key: 'left', label: 'Left', viewMode: 'elevation_left' },
 27→  { key: 'right', label: 'Right', viewMode: 'elevation_right' },
 28→  { key: 'section', label: 'Section', viewMode: 'section_view' },
 29→];
 30→
 31→const toolItems = [
 32→  { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
 33→  { tool: TOOLS.DIMENSION, label: 'Dimension', shortcut: 'M', Icon: DimensionIcon },
 34→  { tool: TOOLS.WALL, label: 'Wall', shortcut: 'W', Icon: WallIcon },
 35→  { tool: TOOLS.BEAM, label: 'Beam', shortcut: 'B', Icon: BeamIcon },
 36→  { tool: TOOLS.STAIR, label: 'Stair', shortcut: 'T', Icon: StairIcon },
 37→  { tool: TOOLS.SECTION, label: 'Section Cut', shortcut: 'Q', Icon: SectionCutIcon },
 38→  { tool: TOOLS.SLAB, label: 'Slab', shortcut: 'S', Icon: SlabIcon },
 39→  { tool: TOOLS.ROOM, label: 'Room', shortcut: 'R', Icon: RoomIcon },
 40→  { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D', Icon: DoorIcon },
 41→  { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N', Icon: WindowIcon },
 42→  { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C', Icon: ColumnIcon },
 43→  { tool: TOOLS.LANDING, label: 'Landing', shortcut: 'L', Icon: LandingIcon },
 44→  { tool: TOOLS.RAILING, label: 'Railing', shortcut: 'H', Icon: RailingIcon },
 45→];
 46→
 47→export default function Toolbar({
 48→  onNew,
 49→  onSave,
 50→  onLoad,
 51→  isSidebarCollapsed,
 52→  isPropertiesCollapsed,
 53→  onToggleSidebar,
 54→  onToggleProperties,
 55→}) {
 56→  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, toolState, dispatch: editorDispatch } = useEditor();
 57→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 58→  const {
 59→    canCopySelection,
 60→    canPaste,
 61→    copySelection,
 62→    cutSelection,
 63→    beginPaste,
 64→  } = usePlanClipboardController();
 65→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 66→
 67→  const fixtureItems = [
 68→    { fixtureType: FIXTURE_TYPES.KITCHEN_TOP, label: 'Kitchen Top', Icon: KitchenTopIcon },
 69→    { fixtureType: FIXTURE_TYPES.TOILET, label: 'Toilet', Icon: ToiletIcon },
 70→    { fixtureType: FIXTURE_TYPES.LAVATORY, label: 'Lavatory', Icon: LavatoryIcon },
 71→    { fixtureType: FIXTURE_TYPES.TABLE, label: 'Table', Icon: TableIcon },
 72→    { fixtureType: FIXTURE_TYPES.TV, label: 'TV', Icon: TVIcon },
 73→    { fixtureType: FIXTURE_TYPES.SOFA, label: 'Sofa', Icon: SofaIcon },
 74→    { fixtureType: FIXTURE_TYPES.BED, label: 'Bed', Icon: BedIcon },
 75→  ];
 76→
 77→  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
 78→
 79→  const handleUndo = useCallback(() => {
 80→    if (!canUndo) return;
 81→    dispatch({ type: 'UNDO' });
 82→    editorDispatch({ type: 'DESELECT' });
 83→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
 84→  }, [canUndo, dispatch, editorDispatch]);
 85→
 86→  const handleRedo = useCallback(() => {
 87→    if (!canRedo) return;
 88→    dispatch({ type: 'REDO' });
 89→    editorDispatch({ type: 'DESELECT' });
 90→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
 91→  }, [canRedo, dispatch, editorDispatch]);
 92→
 93→  const handleDetectRooms = () => {
 94→    const floor = project.floors.find(f => f.id === activeFloorId);
 95→    if (!floor || floor.walls.length < 3) {
 96→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
 97→      return;
 98→    }
 99→    const detected = detectRooms(floor.walls, floor.columns || []);
100→    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
101→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
102→    editorDispatch({ type: 'DESELECT' });
103→    editorDispatch({
104→      type: 'SET_STATUS_MESSAGE',
105→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
106→    });
107→  };
108→
109→  useEffect(() => {
110→    const handleKeyDown = (e) => {
111→      if (!(e.ctrlKey || e.metaKey)) return;
112→      if (isTypingTarget(e.target)) return;
113→
114→      const key = e.key.toLowerCase();
115→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
116→      const isUndo = key === 'z' && !e.shiftKey;
117→      if (!isUndo && !isRedo) return;
118→
119→      e.preventDefault();
120→      if (isRedo) {
121→        handleRedo();
122→        return;
123→      }
124→      handleUndo();
125→    };
126→
127→    window.addEventListener('keydown', handleKeyDown);
128→    return () => window.removeEventListener('keydown', handleKeyDown);
129→  }, [handleRedo, handleUndo]);
130→
131→  const activeViewKey = workspaceMode === 'sheet' ? 'sheets' :
132→    viewModes.find(v => v.viewMode === viewMode)?.key || 'plan';
133→
134→  return (
135→    <div className={styles.toolbar}>
136→      {/* File & clipboard actions */}
137→      <div className={styles.group}>
138→        <button className={styles.btn} onClick={onNew} title="New Project">
139→          <NewIcon className={styles.icon} />
140→        </button>
141→        <button
142→          className={styles.btn}
143→          onClick={handleUndo}
144→          disabled={!canUndo}
145→          title="Undo (Ctrl+Z)"
146→          aria-label="Undo"
147→        >
148→          <UndoIcon className={styles.icon} />
149→        </button>
150→        <button
151→          className={styles.btn}
152→          onClick={handleRedo}
153→          disabled={!canRedo}
154→          title="Redo (Ctrl+Shift+Z)"
155→          aria-label="Redo"
156→        >
157→          <RedoIcon className={styles.icon} />
158→        </button>
159→        <button
160→          className={styles.saveBtn}
161→          onClick={onSave}
162→          title="Save (Ctrl+S)"
163→          data-dirty={isDirty}
164→        >
165→          <SaveIcon className={styles.icon} />
166→        </button>
167→        <div className={styles.divider} />
168→        <button className={styles.btn} onClick={onLoad} title="Load Project">
169→          <LoadIcon className={styles.icon} />
170→        </button>
171→        <button
172→          className={styles.btn}
173→          onClick={copySelection}
174→          disabled={!canCopySelection}
175→          title="Copy (Ctrl+C)"
176→        >
177→          <CopyIcon className={styles.icon} />
178→        </button>
179→        <button
180→          className={styles.btn}
181→          onClick={cutSelection}
182→          disabled={!canCopySelection}
183→          title="Cut (Ctrl+X)"
184→        >
185→          <CutIcon className={styles.icon} />
186→        </button>
187→        <button
188→          className={styles.btn}
189→          onClick={() => beginPaste()}
190→          disabled={!canPaste}
191→          title="Paste (Ctrl+V)"
192→        >
193→          <PasteIcon className={styles.icon} />
194→        </button>
195→      </div>
196→
197→      {/* View mode segmented control */}
198→      <div className={styles.segmentedGroup}>
199→        {viewModes.map(({ key, label, viewMode: vm }) => (
200→          <button
201→            key={key}
202→            className={activeViewKey === key ? styles.segmentedBtnActive : styles.segmentedBtn}
203→            onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: vm })}
204→            title={`${label} View`}
205→          >
206→            {label}
207→          </button>
208→        ))}
209→        <button
210→          className={activeViewKey === 'sheets' ? styles.segmentedBtnActive : styles.segmentedBtn}
211→          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
212→          title="Sheet Workspace"
213→        >
214→          Sheets
215→        </button>
216→      </div>
217→
218→      {/* Tool palette - inline row of 12 icons */}
219→      <div className={styles.toolPalette}>
220→        <span className={styles.groupLabel}>Tools</span>
221→        {toolItems.map(({ tool, label, shortcut, Icon }) => (
222→          <button
223→            key={tool}
224→            className={activeTool === tool ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
225→            onClick={() => setTool(tool)}
226→            disabled={!isPlanView}
227→            title={`${label} (${shortcut})`}
228→            aria-label={label}
229→          >
230→            <Icon className={styles.toolPaletteIcon} />
231→          </button>
232→        ))}
233→      </div>
234→
235→      {/* Fixtures palette */}
236→      <div className={styles.fixturePalette}>
237→        <span className={styles.fixturePaletteLabel}>Fixtures</span>
238→        {fixtureItems.map(({ fixtureType, label, Icon }) => {
239→          const isActive = activeTool === TOOLS.FIXTURE && toolState.fixtureType === fixtureType;
240→          return (
241→            <button
242→              key={fixtureType}
243→              className={isActive ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
244→              onClick={() => {
245→                editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
246→                editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType, previewRotation: 0 } });
247→              }}
248→              disabled={!isPlanView}
249→              title={`${label} (F)`}
250→              aria-label={label}
251→            >
252→              <Icon className={styles.toolPaletteIcon} />
253→            </button>
254→          );
255→        })}
256→      </div>
257→
258→      {/* Panel toggles & utility toggles */}
259→      <div className={styles.group}>
260→        <span className={styles.groupLabel}>Panels</span>
261→        <button
262→          className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''}`}
263→          onClick={onToggleSidebar}
264→          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
265→          aria-label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
266→        >
267→          <SidebarIcon className={styles.icon} />
268→        </button>
269→        <button
270→          className={`${styles.toggleBtn} ${!isPropertiesCollapsed ? styles.toggleActive : ''}`}
271→          onClick={onToggleProperties}
272→          title={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
273→          aria-label={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
274→        >
275→          <PropertiesIcon className={styles.icon} />
276→        </button>
277→        <div className={styles.divider} />
278→        <span className={styles.groupLabel}>Display</span>
279→        <button
280→          className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
281→          onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
282→          title="Toggle Grid"
283→          aria-label="Toggle Grid"
284→        >
285→          <GridIcon className={styles.icon} />
286→        </button>
287→        <button
288→          className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
289→          onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
290→          title="Toggle Snap"
291→          aria-label="Toggle Snap"
292→        >
293→          <SnapIcon className={styles.icon} />
294→        </button>
295→        <button
296→          className={styles.btn}
297→          onClick={handleDetectRooms}
298→          title="Auto-detect Rooms"
299→          disabled={!isPlanView}
300→          aria-label="Auto-detect Rooms"
301→        >
302→          <DetectRoomsIcon className={styles.icon} />
303→        </button>
304→      </div>
305→
306→      <div className={styles.spacer} />
307→    </div>
308→  );
309→}
310→

  1→import { useState } from 'react';
  2→import { useProject } from '@/app/ProjectProvider';
  3→import { useEditor } from '@/app/EditorProvider';
  4→import { getBeamDisplayLabel } from '@/domain/beamLabels';
  5→import { getColumnListLabel } from '@/domain/columnLabels';
  6→import { createFloorAboveHighest, getFloorElevation, getFloorLevelIndex, getOrderedFloors } from '@/domain/floorModels';
  7→import { createSheet, getSheetDisplayLabel } from '@/domain/sheetModels';
  8→import { getSlabDisplayLabel } from '@/domain/slabLabels';
  9→import { getStairDisplayLabel } from '@/domain/stairLabels';
 10→import { getLandingDisplayLabel } from '@/domain/landingLabels';
 11→import { getAnnotationDisplayLabel } from '@/annotations/format';
 12→import styles from './Sidebar.module.css';
 13→
 14→function ChevronSvg({ collapsed }) {
 15→  return (
 16→    <span className={`${styles.chevron} ${collapsed ? styles.chevronCollapsed : ''}`}>
 17→      <svg viewBox="0 0 14 14" aria-hidden="true" className={styles.chevronIcon}>
 18→        <path
 19→          d="M5 3.5l4 3.5-4 3.5"
 20→          fill="none"
 21→          stroke="currentColor"
 22→          strokeWidth="1.5"
 23→          strokeLinecap="round"
 24→          strokeLinejoin="round"
 25→        />
 26→      </svg>
 27→    </span>
 28→  );
 29→}
 30→
 31→function DuplicateIcon() {
 32→  return (
 33→    <svg viewBox="0 0 14 14" aria-hidden="true" className={styles.floorActionIcon}>
 34→      <rect x="5" y="5" width="7" height="7" rx="1" fill="none" stroke="currentColor" strokeWidth="1.2" />
 35→      <path d="M2 9V3a1 1 0 0 1 1-1h6" fill="none" stroke="currentColor" strokeWidth="1.2" />
 36→    </svg>
 37→  );
 38→}
 39→
 40→function TrashIcon() {
 41→  return (
 42→    <svg viewBox="0 0 14 14" aria-hidden="true" className={styles.floorActionIcon}>
 43→      <path d="M3 4.5h8M5.5 4.5V3a.5.5 0 0 1 .5-.5h2a.5.5 0 0 1 .5.5v1.5" fill="none" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round" />
 44→      <path d="M4 4.5l.5 7.5a.5.5 0 0 0 .5.5h4a.5.5 0 0 0 .5-.5l.5-7.5" fill="none" stroke="currentColor" strokeWidth="1.2" />
 45→    </svg>
 46→  );
 47→}
 48→
 49→function Section({ title, count, collapsed, onToggle, collapsible = true, action, children }) {
 50→  return (
 51→    <div className={styles.section}>
 52→      <div className={styles.sectionHeaderRow}>
 53→        <button
 54→          type="button"
 55→          className={`${styles.sectionHeader} ${collapsible ? styles.sectionHeaderClickable : ''} ${styles.sectionHeaderContent}`}
 56→          onClick={collapsible ? onToggle : undefined}
 57→          aria-expanded={!collapsed}
 58→        >
 59→          {collapsible ? <ChevronSvg collapsed={collapsed} /> : <span style={{ width: 14 }} />}
 60→          <span className={styles.sectionTitle}>{title}</span>
 61→          {count !== undefined && <span className={styles.count}>{count}</span>}
 62→        </button>
 63→        {action}
 64→      </div>
 65→      {!collapsed && children}
 66→    </div>
 67→  );
 68→}
 69→
 70→export default function Sidebar() {
 71→  const { project, dispatch, duplicateFloor } = useProject();
 72→  const { activeFloorId, activeSheetId, selectedId, workspaceMode, dispatch: editorDispatch } = useEditor();
 73→  const orderedFloors = getOrderedFloors(project);
 74→  const floor = orderedFloors.find((entry) => entry.id === activeFloorId) || null;
 75→  const [collapsedSections, setCollapsedSections] = useState({
 76→    floors: false,
 77→    sheets: false,
 78→    slabs: false,
 79→    walls: false,
 80→    annotations: false,
 81→    beams: false,
 82→    stairs: false,
 83→    landings: false,
 84→    doors: false,
 85→    windows: false,
 86→    columns: false,
 87→    rooms: false,
 88→  });
 89→
 90→  const selectObject = (id, type) => {
 91→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
 92→  };
 93→
 94→  const selectFloor = (floorId) => {
 95→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 96→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
 97→    editorDispatch({ type: 'SELECT_OBJECT', id: floorId, objectType: 'floor' });
 98→  };
 99→
100→  const setActiveFloor = (floorId) => {
101→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
102→  };
103→
104→  const addFloor = () => {
105→    const nextFloor = createFloorAboveHighest(project.floors || []);
106→    dispatch({ type: 'FLOOR_ADD', floor: nextFloor });
107→    selectFloor(nextFloor.id);
108→  };
109→
110→  const handleDuplicateFloor = (floorToDuplicate) => {
111→    const duplicatedFloor = duplicateFloor(floorToDuplicate.id);
112→    if (!duplicatedFloor) return;
113→
114→    dispatch({ type: 'FLOOR_DUPLICATE', floor: duplicatedFloor });
115→    selectFloor(duplicatedFloor.id);
116→  };
117→
118→  const handleDeleteFloor = (floorToDelete) => {
119→    if ((project.floors || []).length <= 1) return;
120→
121→    const confirmed = window.confirm(`Delete "${floorToDelete.name}"?`);
122→    if (!confirmed) return;
123→
124→    const remainingFloors = orderedFloors.filter((entry) => entry.id !== floorToDelete.id);
125→    const fallbackFloor = remainingFloors[0] || null;
126→
127→    dispatch({
128→      type: 'FLOOR_DELETE',
129→      floorId: floorToDelete.id,
130→      fallbackFloorId: fallbackFloor?.id ?? null,
131→    });
132→
133→    if (floorToDelete.id === activeFloorId && fallbackFloor) {
134→      if (workspaceMode === 'model') {
135→        selectFloor(fallbackFloor.id);
136→      } else {
137→        setActiveFloor(fallbackFloor.id);
138→      }
139→    }
140→  };
141→
142→  const addSheet = () => {
143→    const nextIndex = (project.sheets || []).length + 1;
144→    const sheet = createSheet(`Sheet ${nextIndex}`, {
145→      drawingName: `Drawing ${nextIndex}`,
146→      number: `A${String(nextIndex).padStart(2, '0')}`,
147→    });
148→    dispatch({ type: 'SHEET_ADD', sheet });
149→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
150→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
151→    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
152→  };
153→
154→  const toggleSection = (sectionKey) => {
155→    setCollapsedSections(current => ({
156→      ...current,
157→      [sectionKey]: !current[sectionKey],
158→    }));
159→  };
160→
161→  return (
162→    <div className={styles.sidebar}>
163→      <Section title="Project" collapsible={false}>
164→        <input
165→          className={styles.projectName}
166→          value={project.name}
167→          onChange={(e) => dispatch({ type: 'PROJECT_SET_NAME', name: e.target.value })}
168→        />
169→      </Section>
170→
171→      <Section
172→        title="Floors"
173→        count={orderedFloors.length}
174→        collapsed={collapsedSections.floors}
175→        onToggle={() => toggleSection('floors')}
176→        action={
177→          <button type="button" className={styles.sectionAddBtn} onClick={addFloor} title="Add Floor">+</button>
178→        }
179→      >
180→        {orderedFloors.map((entry) => (
181→          <div
182→            key={entry.id}
183→            className={`${styles.floorCard} ${entry.id === activeFloorId ? styles.floorCardActive : ''}`}
184→          >
185→            <button
186→              type="button"
187→              className={styles.floorButton}
188→              onClick={() => selectFloor(entry.id)}
189→            >
190→              <span className={styles.floorName}>{entry.name}</span>
191→              <span className={styles.floorMeta}>
192→                L{getFloorLevelIndex(entry)} · {Math.round(getFloorElevation(entry))} mm
193→              </span>
194→            </button>
195→            <div className={styles.floorActions}>
196→              <button
197→                type="button"
198→                className={styles.floorActionBtn}
199→                onClick={() => handleDuplicateFloor(entry)}
200→                title={`Duplicate ${entry.name}`}
201→              >
202→                <DuplicateIcon />
203→              </button>
204→              <button
205→                type="button"
206→                className={`${styles.floorActionBtn} ${styles.floorActionDanger}`}
207→                onClick={() => handleDeleteFloor(entry)}
208→                title={`Delete ${entry.name}`}
209→                disabled={orderedFloors.length <= 1}
210→              >
211→                <TrashIcon />
212→              </button>
213→            </div>
214→          </div>
215→        ))}
216→      </Section>
217→
218→      <Section
219→        title="Sheets"
220→        count={(project.sheets || []).length}
221→        collapsed={collapsedSections.sheets}
222→        onToggle={() => toggleSection('sheets')}
223→        action={
224→          <button type="button" className={styles.sectionAddBtn} onClick={addSheet} title="Add Sheet">+</button>
225→        }
226→      >
227→        {(project.sheets || []).map((sheet, index) => (
228→          <div
229→            key={sheet.id}
230→            className={`${styles.item} ${workspaceMode === 'sheet' && activeSheetId === sheet.id ? styles.itemSelected : ''}`}
231→            onClick={() => {
232→              editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
233→              editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
234→              editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
235→            }}
236→          >
237→            {getSheetDisplayLabel(sheet, index)}
238→          </div>
239→        ))}
240→      </Section>
241→
242→      {floor && (
243→        <>
244→          <div className={styles.contextHeader}>Floor: {floor.name}</div>
245→
246→          <Section
247→            title="Slabs"
248→            count={(floor.slabs || []).length}
249→            collapsed={collapsedSections.slabs}
250→            onToggle={() => toggleSection('slabs')}
251→          >
252→            {(floor.slabs || []).map(slab => (
253→              <div
254→                key={slab.id}
255→                className={`${styles.item} ${selectedId === slab.id ? styles.itemSelected : ''}`}
256→                onClick={() => selectObject(slab.id, 'slab')}
257→              >
258→                {getSlabDisplayLabel(slab)}
259→              </div>
260→            ))}
261→          </Section>
262→
263→          <Section
264→            title="Walls"
265→            count={floor.walls.length}
