 39→function useUnits() {
 40→  const [unit, setUnit] = useState('mm');
 41→  const isMm = unit === 'mm';
 42→  return {
 43→    unit,
 44→    setUnit,
 45→    suffix: isMm ? 'mm' : 'm',
 46→    toDisplay: (mm) => isMm ? +mm.toFixed(1) : +(mm / 1000).toFixed(4),
 47→    fromDisplay: (v) => isMm ? v : v * 1000,
 48→    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
 49→  };
 50→}
